"""
Custom exceptions for SEC-081 Unified Authentication Module.

These exceptions provide granular error handling for authentication
operations, enabling proper audit logging and security monitoring.
"""

from typing import Optional


class AuthenticationError(Exception):
    """
    Base exception for all authentication errors.

    All authentication failures should inherit from this class
    to enable centralized error handling and audit logging.

    Attributes:
        message: Human-readable error description
        error_code: Machine-readable error code for logging
        details: Additional context (never include sensitive data)
    """

    def __init__(
        self,
        message: str,
        error_code: str = "AUTH_ERROR",
        details: Optional[dict] = None
    ):
        self.message = message
        self.error_code = error_code
        self.details = details or {}
        super().__init__(self.message)

    def to_dict(self) -> dict:
        """Convert to dictionary for logging (excludes sensitive data)."""
        return {
            "error_code": self.error_code,
            "message": self.message,
            "details": self.details,
        }


# =============================================================================
# TOKEN EXCEPTIONS
# =============================================================================

class TokenExpiredError(AuthenticationError):
    """Token has expired and cannot be used."""

    def __init__(self, message: str = "Token has expired", jti: Optional[str] = None):
        super().__init__(
            message=message,
            error_code="TOKEN_EXPIRED",
            details={"jti": jti} if jti else {}
        )


class TokenRevokedError(AuthenticationError):
    """Token has been revoked (logout, session termination)."""

    def __init__(self, message: str = "Token has been revoked", jti: Optional[str] = None):
        super().__init__(
            message=message,
            error_code="TOKEN_REVOKED",
            details={"jti": jti} if jti else {}
        )


class InvalidAlgorithmError(AuthenticationError):
    """
    Token uses a blocked or unsupported algorithm.

    This exception is raised for:
    - "none" algorithm attacks (CVE-2015-9235)
    - HS256/HS384/HS512 in multi-tenant context
    - Algorithm confusion attacks
    """

    def __init__(
        self,
        message: str = "Invalid or blocked algorithm",
        algorithm: Optional[str] = None
    ):
        super().__init__(
            message=message,
            error_code="INVALID_ALGORITHM",
            details={"algorithm": algorithm} if algorithm else {}
        )


class InvalidSignatureError(AuthenticationError):
    """Token signature verification failed."""

    def __init__(self, message: str = "Invalid token signature"):
        super().__init__(
            message=message,
            error_code="INVALID_SIGNATURE",
            details={}
        )


class InvalidClaimsError(AuthenticationError):
    """Token claims validation failed (missing required claims, invalid values)."""

    def __init__(
        self,
        message: str = "Invalid token claims",
        missing_claims: Optional[list] = None,
        invalid_claims: Optional[list] = None
    ):
        details = {}
        if missing_claims:
            details["missing_claims"] = missing_claims
        if invalid_claims:
            details["invalid_claims"] = invalid_claims
        super().__init__(
            message=message,
            error_code="INVALID_CLAIMS",
            details=details
        )


class TokenNotFoundError(AuthenticationError):
    """No token provided in request."""

    def __init__(self, message: str = "Authentication token not provided"):
        super().__init__(
            message=message,
            error_code="TOKEN_NOT_FOUND",
            details={}
        )


class KeyNotFoundError(AuthenticationError):
    """JWT signing/verification key not found."""

    def __init__(self, message: str = "JWT key not configured", key_type: str = "unknown"):
        super().__init__(
            message=message,
            error_code="KEY_NOT_FOUND",
            details={"key_type": key_type}
        )


