class TenantContextError(AuthenticationError):
    """Error establishing tenant context (Layer 1 failure)."""

    def __init__(
        self,
        message: str = "Failed to establish tenant context",
        org_id: Optional[str] = None
    ):
        super().__init__(
            message=message,
            error_code="TENANT_CONTEXT_ERROR",
            details={"org_id": org_id} if org_id else {}
        )


class OrganizationMismatchError(AuthenticationError):
    """Request organization doesn't match authenticated context."""

    def __init__(
        self,
        message: str = "Organization mismatch",
        expected_org_id: Optional[str] = None,
        provided_org_id: Optional[str] = None
    ):
        super().__init__(
            message=message,
            error_code="ORG_MISMATCH",
            details={
                "expected": expected_org_id,
                "provided": provided_org_id
            }
        )


